#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        unsigned long long n, res = 1ULL;
        scanf("%llu", &n);
        for (unsigned long long i = 1; i <= n; ++i) res *= i;
        printf("%llu\n", res);
    }
    return 0;
}

